```
@freshness_policy_sensor(
    asset_selection=AssetSelection.all(),
)
def slack_on_freshness_policy_status(context: FreshnessPolicySensorContext):
    if context.minutes_late > 10 and context.previous_minutes_late < 10:
        # send failure slack message
        pass
    if context.minutes_late == 0 and context.previous_minutes_late != 0:
        # send success slack message
        pass
```

