        let chain_reader = [hash_mode_u8];
        let mut chained = chain_reader.chain(fd);

        let cond = { 
            if SinglesigHashMode::from_u8(hash_mode_u8).is_some() {
                let cond = SinglesigSpendingCondition::consensus_deserialize(&mut chained)?;
...
```

