How about having status as a property for `SqueueResult`? Maybe something like this could be more clear:
```python
class SqueueResult(BaseModel):
    """Model used to parse SLURM squeue output."""

    jobs: List[SqueueJob]
    jobs_status_distribution: Optional[Dict[str, float]]

    @validator("jobs_status_distribution", always=True)
    def set_jobs_status_distribution(
        cls, _: Optional[List[SqueueJob]], values: Dict[str, Any]
    ) -> Optional[Dict[str, float]]:
        """Set the job status distribution."""
        jobs: List[SqueueJob] = values["jobs"]
        status_distribution: Dict[str, float] = {}
        for job in jobs:
            status_distribution[job.status] = status_distribution.get(job.status, 0) + 1
        for status in status_distribution:
            status_distribution[status] = round(status_distribution[status] / len(jobs), 2)
            return status_distribution

    @property
    def is_ongoing(self):
        return bool(
            self.jobs_status_distribution.get(SlurmJobStatus.RUNNING)
            or self.jobs_status_distribution.get(SlurmJobStatus.PENDING)
        )

    @property
    def only_one_status(self):
        return len(self.jobs_status_distribution) == 1

    @property
    def status(self):
        """Aggregates the statuses of all jobs into a status for a whole case. If multiple statuses
        the order is decided by STATUS_PRIORITY_LIST."""
        if self.only_one_status:
            only_status: str = self.jobs_status_distribution.popitem()[0]
            return SlurmTrailblazerStatusMap[only_status]

        aggregation_status = SlurmJobStatus.FAILED
        for status in STATUS_PRIORITY_LIST:
            if status in self.jobs_status_distribution.keys():
                aggregation_status = status
                break

        if aggregation_status == SlurmJobStatus.FAILED and self.is_ongoing:
            return TrailblazerStatus.ERROR
        return SlurmTrailblazerStatusMap[aggregation_status]


STATUS_PRIORITY_LIST = [
    SlurmJobStatus.FAILED,
    SlurmJobStatus.TIME_OUT,
    SlurmJobStatus.CANCELLED,
    SlurmJobStatus.RUNNING,
]

FAILED_STATUSES = [SlurmJobStatus.FAILED, SlurmJobStatus.TIME_OUT]

SlurmTrailblazerStatusMap: Dict[str, str] = {
    SlurmJobStatus.FAILED: TrailblazerStatus.FAILED,
    SlurmJobStatus.TIME_OUT: TrailblazerStatus.FAILED,
    SlurmJobStatus.COMPLETED: TrailblazerStatus.COMPLETED,
    SlurmJobStatus.PENDING: TrailblazerStatus.PENDING,
    SlurmJobStatus.RUNNING: TrailblazerStatus.RUNNING,
    SlurmJobStatus.CANCELLED: TrailblazerStatus.CANCELLED,
}

```

